
/*
  DilAvatar v12 — Yüksek Kaliteli Görsel Zemin + Hareketli Katmanlar
  ------------------------------------------------------------------
  Tek dosya, çevrimdışı, dış bağımlılıksız.
  HTML + CSS + SVG + Vanilla JavaScript.

  Mantık:
  - Erkek avatar zemininde kaliteli portre görseli kullanılır.
  - Göz kapakları, kaş, dudak/ağız ve çene hissi üst SVG katmanıdır.
  - Tüm hizalar ayar panelinden düzenlenir ve "Ayarları kaydet" ile localStorage'a yazılır.

  Kullanım:
    DilAvatar.mount("avatarHost");
    DilAvatar.setGender("erkek");
    DilAvatar.speakText("merhaba bugün ingilizce çalışıyoruz", 3200);

  Ayar paneli:
    DilAvatar.mountControlPanel("panelHost");
*/
(function(global){
  "use strict";

  var STORAGE_KEY = "DilAvatar.image.v12.settings";
  var GENDER_KEY  = "DilAvatar.image.v12.gender";
  var COMMON_SETTINGS_KEY = "DilAvatar.settings";
  var COMMON_GENDER_KEY = "DilAvatar.gender";
  var BC_NAME = "DilAvatar.settings";
  var broadcast = null;

  var BASE_MALE_IMAGE = "data:image/png;base64,";

  var DEFAULTS = {
    erkek: {
      title: "Erkek Avatar",
      theme: "#2dd4bf",
      mode: "image",
      baseImage: BASE_MALE_IMAGE,

      // Ağız / dudak
      mouthX: 500,
      mouthY: 610,
      mouthScale: 1,
      mouthWidth: 98,
      mouthHeight: 26,
      mouthRotate: 0,
      mouthOpacity: 0.86,
      lipColor: "#c38b74",
      lipShadow: "#775644",
      mouthInner: "#513129",

      // Göz kapağı
      leftEyeX: 414,
      leftEyeY: 418,
      rightEyeX: 586,
      rightEyeY: 418,
      eyeW: 82,
      eyeH: 24,
      eyeStroke: 6,
      eyeCurve: 9,
      eyeOpacity: 0.96,
      eyelidColor: "#eec19b",

      // Kaş
      browVisible: true,
      browOpacity: 0.62,
      browWidth: 96,
      browHeight: 18,
      browPeak: 12,
      browStroke: 10,
      leftBrowX: 414,
      leftBrowY: 360,
      rightBrowX: 586,
      rightBrowY: 360,
      leftBrowRotate: -2,
      rightBrowRotate: 2,
      browColor: "#766f66",

      // Çene / alt yüz hareket hissi
      jawEnabled: true,
      jawX: 500,
      jawY: 704,
      jawWidth: 150,
      jawHeight: 46,
      jawOpacity: 0.12,
      jawColor: "#8f5f47",
      jawRest: 0,
      jawClosed: 1,
      jawWide: 4,
      jawRound: 6,
      jawOpen: 10,
      jawTeeth: 5
    },

    // Kadın yedek avatar: zemin SVG, aynı overlay sistemiyle çalışır.
    kadin: {
      title: "Kadın Avatar",
      theme: "#3b82f6",
      mode: "femaleVector",

      mouthX: 500,
      mouthY: 548,
      mouthScale: 1,
      mouthWidth: 108,
      mouthHeight: 34,
      mouthRotate: 0,
      mouthOpacity: 1,
      lipColor: "#d94b62",
      lipShadow: "#922038",
      mouthInner: "#3b0f1b",

      leftEyeX: 410,
      leftEyeY: 405,
      rightEyeX: 590,
      rightEyeY: 405,
      eyeW: 76,
      eyeH: 24,
      eyeStroke: 7,
      eyeCurve: 14,
      eyeOpacity: 1,
      eyelidColor: "#ffd7ae",

      browVisible: true,
      browOpacity: 1,
      browWidth: 86,
      browHeight: 24,
      browPeak: 18,
      browStroke: 12,
      leftBrowX: 410,
      leftBrowY: 345,
      rightBrowX: 590,
      rightBrowY: 345,
      leftBrowRotate: -8,
      rightBrowRotate: 8,
      browColor: "#5b2a1c",

      jawEnabled: true,
      jawX: 500,
      jawY: 628,
      jawWidth: 126,
      jawHeight: 34,
      jawOpacity: 0.08,
      jawColor: "#9b5d43",
      jawRest: 0,
      jawClosed: 1,
      jawWide: 3,
      jawRound: 4,
      jawOpen: 8,
      jawTeeth: 4
    }
  };

  var state = {
    host: null,
    root: null,
    artWrap: null,
    gender: "erkek",
    mouth: "rest",
    speakingTimer: null,
    thinkingTimer: null,
    blinkTimer: null,
    blinkOffTimer: null,
    isBlinking: false,
    settings: null,
    controls: [],
    dirty: false,
    saveStatusEl: null
  };

  function clone(obj){ return JSON.parse(JSON.stringify(obj)); }

  function safeGet(key, fallback){
    try {
      var v = global.localStorage && global.localStorage.getItem(key);
      return v == null ? fallback : v;
    } catch(e){ return fallback; }
  }

  function safeSet(key, value){
    try {
      if (global.localStorage) global.localStorage.setItem(key, value);
    } catch(e){}
  }

  function safeRemove(key){
    try {
      if (global.localStorage) global.localStorage.removeItem(key);
    } catch(e){}
  }

  function mergeIntoDefaults(target, incoming){
    if (!incoming) return;
    if (incoming.settings) incoming = incoming.settings;
    ["erkek","kadin"].forEach(function(g){
      if (incoming[g]) Object.keys(incoming[g]).forEach(function(k){
        target[g][k] = incoming[g][k];
      });
    });
  }

  function loadSettings(){
    state.settings = clone(DEFAULTS);

    var saved = safeGet(STORAGE_KEY, null);
    if (!saved) saved = safeGet(COMMON_SETTINGS_KEY, null);

    if (saved) {
      try { mergeIntoDefaults(state.settings, JSON.parse(saved)); } catch(e){}
    }

    var g = safeGet(GENDER_KEY, safeGet(COMMON_GENDER_KEY, "erkek"));
    state.gender = (g === "kadin" || g === "erkek") ? g : "erkek";
  }

  function makePayload(){
    return {
      schema: "image-v12",
      gender: state.gender,
      updatedAt: new Date().toISOString(),
      settings: state.settings
    };
  }

  function saveSettings(){
    var json = JSON.stringify(makePayload());
    safeSet(STORAGE_KEY, json);
    safeSet(COMMON_SETTINGS_KEY, json);
    safeSet(GENDER_KEY, state.gender);
    safeSet(COMMON_GENDER_KEY, state.gender);
    try {
      if (broadcast) broadcast.postMessage({ type: "settings", payload: makePayload(), gender: state.gender });
    } catch(e){}
  }

  function markDirty(){
    state.dirty = true;
    updateSaveStatus("Kaydedilmedi");
  }

  function saveFromPanel(){
    saveSettings();
    state.dirty = false;
    updateSaveStatus("Kaydedildi: " + new Date().toLocaleTimeString("tr-TR"));
  }

  function updateSaveStatus(text){
    if (!state.saveStatusEl) return;
    state.saveStatusEl.textContent = text || (state.dirty ? "Kaydedilmedi" : "Kaydedildi");
    state.saveStatusEl.setAttribute("data-dirty", state.dirty ? "1" : "0");
  }

  function current(){ return state.settings[state.gender]; }

  function clamp(n, min, max){
    n = Number(n);
    if (!isFinite(n)) n = min;
    return Math.max(min, Math.min(max, n));
  }

  function el(tag, attrs, html){
    var node = document.createElement(tag);
    attrs = attrs || {};
    Object.keys(attrs).forEach(function(k){
      if (k === "class") node.className = attrs[k];
      else node.setAttribute(k, attrs[k]);
    });
    if (html != null) node.innerHTML = html;
    return node;
  }

  function injectCss(){
    if (document.getElementById("dil-avatar-style-v12")) return;

    var css = `
      .dil-avatar-box{
        --da-theme:#2dd4bf;
        width:100%;
        max-width:310px;
        min-width:120px;
        margin:0 auto;
        font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
        color:#e5e7eb;
        user-select:none;
      }
      .dil-avatar-frame{
        position:relative;
        width:100%;
        aspect-ratio:1/1;
        border-radius:50%;
        overflow:hidden;
        background:#0b1120;
        border:4px solid var(--da-theme);
        box-shadow:0 20px 40px rgba(0,0,0,.25), inset 0 0 0 1px rgba(255,255,255,.08);
      }
      .dil-avatar-art{
        position:absolute;
        inset:0;
        width:100%;
        height:100%;
        display:block;
      }
      .dil-avatar-base-img{
        object-fit:cover;
        object-position:center center;
      }
      .dil-avatar-switch{
        margin:12px auto 0;
        padding:6px;
        display:flex;
        gap:6px;
        justify-content:center;
        background:rgba(15,23,42,.85);
        border:1px solid rgba(148,163,184,.35);
        border-radius:999px;
        width:max-content;
        max-width:100%;
      }
      .dil-avatar-switch button,
      .dil-avatar-panel button{
        border:0;
        border-radius:999px;
        padding:10px 14px;
        font-weight:800;
        cursor:pointer;
        background:transparent;
        color:#cbd5e1;
      }
      .dil-avatar-switch button.active{
        background:linear-gradient(135deg,#2563eb,#3b82f6);
        color:white;
      }
      .dil-avatar-panel{
        font-family:system-ui,-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;
        background:#0b1120;
        color:#e5e7eb;
        border:1px solid rgba(148,163,184,.25);
        border-radius:18px;
        padding:14px;
        max-width:960px;
      }
      .dil-avatar-panel h3{
        margin:0 0 10px;
        font-size:18px;
      }
      .dil-avatar-grid{
        display:grid;
        grid-template-columns:repeat(auto-fit,minmax(230px,1fr));
        gap:12px;
      }
      .dil-avatar-card{
        background:rgba(15,23,42,.85);
        border:1px solid rgba(148,163,184,.25);
        border-radius:14px;
        padding:12px;
      }
      .dil-avatar-card h4{
        margin:0 0 8px;
        color:#93c5fd;
      }
      .dil-avatar-savebar{
        display:flex;
        align-items:center;
        justify-content:space-between;
        gap:10px;
        flex-wrap:wrap;
        margin:0 0 12px;
        padding:10px;
        border-radius:14px;
        background:rgba(15,23,42,.85);
        border:1px solid rgba(148,163,184,.25);
      }
      .dil-avatar-save-status{
        font-size:13px;
        color:#86efac;
        font-weight:800;
      }
      .dil-avatar-save-status[data-dirty="1"]{
        color:#fbbf24;
      }
      .dil-avatar-row{
        display:grid;
        grid-template-columns:104px 1fr 58px;
        gap:8px;
        align-items:center;
        margin:7px 0;
        font-size:12px;
      }
      .dil-avatar-row input[type=range]{
        width:100%;
      }
      .dil-avatar-row output{
        text-align:right;
        color:#cbd5e1;
        font-variant-numeric:tabular-nums;
      }
      .dil-avatar-small-actions{
        display:flex;
        flex-wrap:wrap;
        gap:8px;
        margin-top:12px;
      }
      .dil-avatar-small-actions button{
        background:#1e293b;
        color:#e5e7eb;
        border-radius:12px;
        padding:9px 12px;
      }
      .dil-avatar-small-actions button.primary{
        background:#2563eb;
        color:#fff;
      }
      .dil-avatar-json{
        width:100%;
        min-height:120px;
        background:#020617;
        color:#dbeafe;
        border:1px solid rgba(148,163,184,.3);
        border-radius:12px;
        padding:10px;
        box-sizing:border-box;
        margin-top:10px;
        font-family:ui-monospace,SFMono-Regular,Menlo,Monaco,Consolas,monospace;
        font-size:12px;
      }
    `;
    document.head.appendChild(el("style", { id:"dil-avatar-style-v12" }, css));
  }

  function setupLiveSync(){
    try {
      if (!broadcast && "BroadcastChannel" in global) {
        broadcast = new BroadcastChannel(BC_NAME);
        broadcast.onmessage = function(ev){
          if (!ev || !ev.data || ev.data.type !== "settings") return;
          if (ev.data.payload) mergeIntoDefaults(state.settings || clone(DEFAULTS), ev.data.payload);
          if (ev.data.gender === "erkek" || ev.data.gender === "kadin") state.gender = ev.data.gender;
          render();
        };
      }
    } catch(e){}

    try {
      global.addEventListener("storage", function(ev){
        if (!ev) return;
        if ([STORAGE_KEY, COMMON_SETTINGS_KEY, GENDER_KEY, COMMON_GENDER_KEY].indexOf(ev.key) === -1) return;
        loadSettings();
        render();
      });
    } catch(e){}
  }

  function jawAmount(){
    var c = current();
    switch(state.mouth){
      case "open": return Number(c.jawOpen || 0);
      case "round": return Number(c.jawRound || 0);
      case "wide": return Number(c.jawWide || 0);
      case "closed": return Number(c.jawClosed || 0);
      case "teeth": return Number(c.jawTeeth || 0);
      default: return Number(c.jawRest || 0);
    }
  }

  function baseLayer(c){
    if (c.mode === "image") {
      return '<img class="dil-avatar-art dil-avatar-base-img" alt="' + c.title + '" src="' + c.baseImage + '">';
    }
    return femaleVectorBase();
  }

  function femaleVectorBase(){
    return `
      <svg class="dil-avatar-art" viewBox="0 0 1000 1000" aria-label="Kadın Avatar">
        <defs>
          <radialGradient id="fbg" cx="50%" cy="35%" r="70%">
            <stop offset="0" stop-color="#ffffff"/>
            <stop offset="1" stop-color="#dbeafe"/>
          </radialGradient>
          <linearGradient id="fskin" x1="0" x2="0" y1="0" y2="1">
            <stop offset="0" stop-color="#ffe2bf"/>
            <stop offset="1" stop-color="#ffd7ae"/>
          </linearGradient>
          <linearGradient id="fhair" x1="0" x2="1" y1="0" y2="1">
            <stop offset="0" stop-color="#7a3b27"/>
            <stop offset="1" stop-color="#5b2a1c"/>
          </linearGradient>
        </defs>
        <rect width="1000" height="1000" fill="url(#fbg)"/>
        <path d="M248 708 C180 575 194 300 355 210 C470 145 642 168 733 286 C821 402 826 616 744 760 C684 866 552 886 500 812 C434 894 304 826 248 708Z" fill="url(#fhair)"/>
        <path d="M356 762 C378 860 622 860 644 762 L644 642 L356 642Z" fill="url(#fskin)"/>
        <path d="M266 1000 C288 848 386 790 500 790 C614 790 712 848 734 1000Z" fill="#0e7490"/>
        <path d="M360 820 L500 1000 L640 820 C590 850 410 850 360 820Z" fill="#fff"/>
        <ellipse cx="296" cy="470" rx="42" ry="66" fill="url(#fskin)"/>
        <ellipse cx="704" cy="470" rx="42" ry="66" fill="url(#fskin)"/>
        <path d="M322 400 C330 250 670 250 678 400 L662 610 C650 750 570 805 500 805 C430 805 350 750 338 610Z" fill="url(#fskin)"/>
        <path d="M322 384 C388 258 556 255 675 382 C672 302 600 210 498 210 C392 210 324 300 322 384Z" fill="url(#fhair)"/>
        <path d="M360 408 C386 380 438 382 462 410 C432 432 388 432 360 408Z" fill="white"/>
        <path d="M538 410 C562 382 614 380 640 408 C612 432 568 432 538 410Z" fill="white"/>
        <circle cx="413" cy="409" r="20" fill="#5b341c"/>
        <circle cx="587" cy="409" r="20" fill="#5b341c"/>
        <circle cx="420" cy="401" r="6" fill="white" opacity=".9"/>
        <circle cx="594" cy="401" r="6" fill="white" opacity=".9"/>
      </svg>
    `;
  }

  function browSvg(c, side){
    if (!c.browVisible) return "";
    var x = side === "left" ? c.leftBrowX : c.rightBrowX;
    var y = side === "left" ? c.leftBrowY : c.rightBrowY;
    var rot = side === "left" ? c.leftBrowRotate : c.rightBrowRotate;
    var w = c.browWidth, h = c.browHeight, p = c.browPeak;
    var flip = side === "left" ? 1 : -1;
    var color = c.browColor || "#766f66";

    return `
      <g transform="translate(${x} ${y}) rotate(${rot}) scale(${flip} 1)" opacity="${c.browOpacity}">
        <path d="M ${-w/2} ${h/2}
                 C ${-w/4} ${-p}, ${w/4} ${-p}, ${w/2} ${h/2}
                 L ${w/2 - 8} ${h/2 + 5}
                 C ${w/5} ${-p + 9}, ${-w/5} ${-p + 9}, ${-w/2 + 8} ${h/2 + 5} Z"
              fill="${color}" opacity=".95"/>
        <path d="M ${-w/2 + 10} ${h/2 + 1}
                 C ${-w/4} ${-p + 8}, ${w/4} ${-p + 8}, ${w/2 - 10} ${h/2 + 1}"
              fill="none" stroke="rgba(255,255,255,.16)" stroke-width="2.5" stroke-linecap="round"/>
      </g>
    `;
  }

  function eyeLidSvg(c, side){
    var x = side === "left" ? c.leftEyeX : c.rightEyeX;
    var y = side === "left" ? c.leftEyeY : c.rightEyeY;
    var w = c.eyeW, h = c.eyeH;
    var lid = c.eyelidColor || "#eec19b";

    return `
      <g opacity="${c.eyeOpacity}">
        <ellipse cx="${x}" cy="${y + 1}" rx="${w/2 + 7}" ry="${Math.max(7, h/2 + 1)}" fill="${lid}" opacity=".96"/>
        <path d="M ${x - w/2} ${y}
                 C ${x - w/4} ${y + c.eyeCurve}, ${x + w/4} ${y + c.eyeCurve}, ${x + w/2} ${y}"
              fill="none" stroke="#4b3a32" stroke-width="${c.eyeStroke}" stroke-linecap="round"/>
        <path d="M ${x - w/2 + 6} ${y - 7}
                 C ${x - w/5} ${y - 14}, ${x + w/5} ${y - 14}, ${x + w/2 - 6} ${y - 7}"
              fill="none" stroke="rgba(90,60,44,.28)" stroke-width="2.5" stroke-linecap="round"/>
      </g>
    `;
  }

  function mouthShapePath(c, shape){
    var w = c.mouthWidth;
    var h = c.mouthHeight;
    var lip = c.lipColor || "#c38b74";
    var shadow = c.lipShadow || "#775644";
    var inner = c.mouthInner || "#513129";

    if (shape === "open") {
      return `
        <path d="M ${-w*.50} 0
                 C ${-w*.25} ${-h*.30}, ${w*.25} ${-h*.30}, ${w*.50} 0
                 C ${w*.26} ${h*.64}, ${-w*.26} ${h*.64}, ${-w*.50} 0Z"
              fill="${lip}" opacity=".96"/>
        <path d="M ${-w*.37} ${h*.02}
                 C ${-w*.18} ${-h*.06}, ${w*.18} ${-h*.06}, ${w*.37} ${h*.02}
                 C ${w*.20} ${h*.40}, ${-w*.20} ${h*.40}, ${-w*.37} ${h*.02}Z"
              fill="${inner}" opacity=".92"/>
        <path d="M ${-w*.22} ${-h*.12}
                 C ${-w*.08} ${-h*.18}, ${w*.08} ${-h*.18}, ${w*.22} ${-h*.12}"
              fill="none" stroke="#fff" stroke-width="3.3" stroke-linecap="round" opacity=".86"/>
      `;
    }

    if (shape === "round") {
      return `
        <path d="M 0 ${-h*.60}
                 C ${w*.25} ${-h*.60}, ${w*.34} ${-h*.18}, ${w*.34} 0
                 C ${w*.34} ${h*.42}, ${w*.18} ${h*.60}, 0 ${h*.60}
                 C ${-w*.18} ${h*.60}, ${-w*.34} ${h*.42}, ${-w*.34} 0
                 C ${-w*.34} ${-h*.18}, ${-w*.25} ${-h*.60}, 0 ${-h*.60}Z"
              fill="${lip}" opacity=".96"/>
        <ellipse cx="0" cy="${h*.04}" rx="${w*.17}" ry="${h*.25}" fill="${inner}" opacity=".92"/>
      `;
    }

    if (shape === "wide") {
      return `
        <path d="M ${-w*.60} 0
                 C ${-w*.28} ${-h*.12}, ${w*.28} ${-h*.12}, ${w*.60} 0
                 C ${w*.30} ${h*.32}, ${-w*.30} ${h*.32}, ${-w*.60} 0Z"
              fill="${lip}" opacity=".84"/>
        <path d="M ${-w*.46} ${h*.05}
                 C ${-w*.18} ${h*.18}, ${w*.18} ${h*.18}, ${w*.46} ${h*.05}"
              fill="none" stroke="${shadow}" stroke-width="4.4" stroke-linecap="round" opacity=".88"/>
      `;
    }

    if (shape === "closed") {
      return `
        <path d="M ${-w*.52} 0
                 C ${-w*.22} ${-h*.18}, ${w*.22} ${-h*.18}, ${w*.52} 0
                 C ${w*.22} ${h*.18}, ${-w*.22} ${h*.18}, ${-w*.52} 0Z"
              fill="${lip}" opacity=".52"/>
        <path d="M ${-w*.46} 0
                 C ${-w*.16} ${h*.04}, ${w*.16} ${h*.04}, ${w*.46} 0"
              fill="none" stroke="${shadow}" stroke-width="4.5" stroke-linecap="round" opacity=".72"/>
      `;
    }

    if (shape === "teeth") {
      return `
        <path d="M ${-w*.50} 0
                 C ${-w*.22} ${-h*.24}, ${w*.22} ${-h*.24}, ${w*.50} 0
                 C ${w*.26} ${h*.34}, ${-w*.26} ${h*.34}, ${-w*.50} 0Z"
              fill="${lip}" opacity=".90"/>
        <rect x="${-w*.24}" y="${-h*.10}" width="${w*.48}" height="${h*.18}" rx="5" fill="#fff" opacity=".96"/>
        <path d="M ${-w*.40} ${h*.05}
                 C ${-w*.12} ${h*.18}, ${w*.12} ${h*.18}, ${w*.40} ${h*.05}"
              fill="none" stroke="${shadow}" stroke-width="4" stroke-linecap="round" opacity=".58"/>
      `;
    }

    // rest
    return `
      <path d="M ${-w*.48} ${h*.01}
               C ${-w*.18} ${-h*.14}, ${w*.18} ${-h*.14}, ${w*.48} ${h*.01}"
            fill="none" stroke="${shadow}" stroke-width="5" stroke-linecap="round" opacity=".86"/>
      <path d="M ${-w*.28} ${h*.09}
               C ${-w*.08} ${h*.18}, ${w*.08} ${h*.18}, ${w*.28} ${h*.09}"
            fill="none" stroke="${lip}" stroke-width="3.4" stroke-linecap="round" opacity=".62"/>
    `;
  }

  function jawSvg(c){
    if (!c.jawEnabled) return "";
    var dy = jawAmount();
    return `
      <g transform="translate(0 ${dy})" opacity="${c.jawOpacity}">
        <ellipse cx="${c.jawX}" cy="${c.jawY}" rx="${c.jawWidth/2}" ry="${c.jawHeight/2}"
                 fill="${c.jawColor || "#8f5f47"}" opacity=".48"/>
        <ellipse cx="${c.jawX}" cy="${c.jawY - 4}" rx="${Math.max(4, c.jawWidth/2 - 9)}" ry="${Math.max(4, c.jawHeight/2 - 8)}"
                 fill="${c.eyelidColor || "#eec19b"}" opacity=".42"/>
      </g>
    `;
  }

  function overlayLayer(c){
    var dy = jawAmount();
    return `
      <svg class="dil-avatar-art" viewBox="0 0 1000 1000" aria-hidden="true">
        ${jawSvg(c)}
        <g id="da-brows">
          ${browSvg(c,"left")}
          ${browSvg(c,"right")}
        </g>
        <g id="da-blink" style="display:${state.isBlinking ? "block" : "none"}">
          ${eyeLidSvg(c,"left")}
          ${eyeLidSvg(c,"right")}
        </g>
        <g id="da-mouth"
           transform="translate(${c.mouthX} ${c.mouthY + dy * 0.68}) rotate(${c.mouthRotate}) scale(${c.mouthScale})"
           opacity="${c.mouthOpacity}">
          ${mouthShapePath(c, state.mouth)}
        </g>
      </svg>
    `;
  }

  function render(){
    if (!state.artWrap) return;
    var c = current();
    if (state.root) state.root.style.setProperty("--da-theme", c.theme || "#2dd4bf");
    state.artWrap.innerHTML = baseLayer(c) + overlayLayer(c);
    updateSwitchButtons();
    updateControlOutputs();
  }

  function mount(target){
    loadSettings();
    injectCss();
    setupLiveSync();

    var host = typeof target === "string" ? document.getElementById(target) : target;
    if (!host) throw new Error("DilAvatar.mount: hedef eleman bulunamadı.");

    host.innerHTML = "";
    state.host = host;

    var root = el("div", { class:"dil-avatar-box" });
    var frame = el("div", { class:"dil-avatar-frame" });
    var artWrap = el("div");
    frame.appendChild(artWrap);

    var sw = el("div", { class:"dil-avatar-switch" });
    var b1 = el("button", { type:"button", "data-da-gender":"kadin" }, "Kadın Avatar");
    var b2 = el("button", { type:"button", "data-da-gender":"erkek" }, "Erkek Avatar");
    b1.onclick = function(){ setGender("kadin"); };
    b2.onclick = function(){ setGender("erkek"); };
    sw.appendChild(b1);
    sw.appendChild(b2);

    root.appendChild(frame);
    root.appendChild(sw);
    host.appendChild(root);

    state.root = root;
    state.artWrap = artWrap;

    render();
    scheduleBlink();
    return root;
  }

  function updateSwitchButtons(){
    if (!state.root) return;
    Array.prototype.forEach.call(state.root.querySelectorAll("[data-da-gender]"), function(b){
      b.classList.toggle("active", b.getAttribute("data-da-gender") === state.gender);
    });
  }

  function setGender(g){
    if (g !== "erkek" && g !== "kadin") return;
    state.gender = g;
    state.mouth = "rest";
    saveSettings();
    render();
  }

  function getGender(){ return state.gender; }

  function setMouth(shape){
    if (["rest","open","round","wide","closed","teeth"].indexOf(shape) < 0) shape = "rest";
    state.mouth = shape;
    render();
  }

  function visemeForChar(ch){
    ch = String(ch || "").toLocaleLowerCase("tr-TR");
    if ("aeâ".indexOf(ch) >= 0) return "open";
    if ("ou".indexOf(ch) >= 0) return "round";
    if ("ıiüöy".indexOf(ch) >= 0) return "wide";
    if ("mbp".indexOf(ch) >= 0) return "closed";
    if ("fv".indexOf(ch) >= 0) return "teeth";
    if (/\s/.test(ch)) return "rest";
    return "rest";
  }

  function clearSpeaking(){
    if (state.speakingTimer) {
      clearTimeout(state.speakingTimer);
      state.speakingTimer = null;
    }
  }

  function speakText(text, durationMs){
    stop(false);
    text = String(text || "");
    var chars = Array.prototype.slice.call(text);
    if (!chars.length) {
      setMouth("rest");
      return;
    }

    var total = Number(durationMs);
    var per = total && isFinite(total) ? total / chars.length : 110;
    per = clamp(per, 60, 150);

    var i = 0;
    function step(){
      if (i >= chars.length) {
        setMouth("rest");
        state.speakingTimer = null;
        return;
      }
      setMouth(visemeForChar(chars[i]));
      i += 1;
      state.speakingTimer = setTimeout(step, per);
    }
    step();
  }

  function blinkOnce(){
    state.isBlinking = true;
    render();
    if (state.blinkOffTimer) clearTimeout(state.blinkOffTimer);
    state.blinkOffTimer = setTimeout(function(){
      state.isBlinking = false;
      render();
    }, 150);
  }

  function scheduleBlink(){
    if (state.blinkTimer) clearTimeout(state.blinkTimer);
    state.blinkTimer = setTimeout(function(){
      blinkOnce();
      scheduleBlink();
    }, 2500 + Math.random() * 2500);
  }

  function thinking(on){
    if (state.thinkingTimer) {
      clearInterval(state.thinkingTimer);
      state.thinkingTimer = null;
    }
    if (!on) {
      setMouth("rest");
      return;
    }
    var flip = false;
    state.thinkingTimer = setInterval(function(){
      flip = !flip;
      setMouth(flip ? "closed" : "rest");
    }, 520);
  }

  function stop(renderNow){
    clearSpeaking();
    if (state.thinkingTimer) {
      clearInterval(state.thinkingTimer);
      state.thinkingTimer = null;
    }
    state.mouth = "rest";
    if (renderNow !== false) render();
  }

  function addRange(parent, key, label, min, max, step){
    var row = el("label", { class:"dil-avatar-row" });
    row.innerHTML =
      '<span>' + label + '</span>' +
      '<input type="range" min="' + min + '" max="' + max + '" step="' + step + '" data-key="' + key + '">' +
      '<output data-out="' + key + '"></output>';
    parent.appendChild(row);

    var input = row.querySelector("input");
    input.addEventListener("input", function(){
      current()[key] = Number(input.value);
      markDirty();
      render();
    });

    state.controls.push({ key:key, input:input, out:row.querySelector("output") });
  }

  function addCheckbox(parent, key, label){
    var row = el("label", { class:"dil-avatar-row" });
    row.innerHTML =
      '<span>' + label + '</span>' +
      '<input type="checkbox" data-key="' + key + '">' +
      '<output data-out="' + key + '"></output>';
    parent.appendChild(row);

    var input = row.querySelector("input");
    input.addEventListener("change", function(){
      current()[key] = !!input.checked;
      markDirty();
      render();
    });

    state.controls.push({ key:key, input:input, out:row.querySelector("output"), checkbox:true });
  }

  function updateControlOutputs(){
    if (!state.controls || !state.controls.length || !state.settings) return;
    var c = current();

    state.controls.forEach(function(ctl){
      if (ctl.checkbox) {
        ctl.input.checked = !!c[ctl.key];
        ctl.out.textContent = c[ctl.key] ? "açık" : "kapalı";
      } else {
        ctl.input.value = c[ctl.key];
        ctl.out.textContent = String(Math.round(Number(c[ctl.key]) * 100) / 100);
      }
    });

    updateSaveStatus(state.dirty ? "Kaydedilmedi" : undefined);
  }

  function mountControlPanel(target){
    if (!state.settings) loadSettings();
    injectCss();

    var host = typeof target === "string" ? document.getElementById(target) : target;
    if (!host) throw new Error("DilAvatar.mountControlPanel: hedef eleman bulunamadı.");

    state.controls = [];

    var panel = el("div", { class:"dil-avatar-panel" });
    panel.innerHTML = `
      <h3>Avatar Ayarlama Paneli</h3>
      <div class="dil-avatar-savebar">
        <button class="primary" data-act="save">Ayarları kaydet</button>
        <span class="dil-avatar-save-status" data-da-save-status data-dirty="0">Kaydedildi</span>
      </div>

      <div class="dil-avatar-grid">
        <div class="dil-avatar-card" data-section="mouth"><h4>Ağız / Dudak</h4></div>
        <div class="dil-avatar-card" data-section="eyes"><h4>Göz Kapağı</h4></div>
        <div class="dil-avatar-card" data-section="brow"><h4>Kaş</h4></div>
        <div class="dil-avatar-card" data-section="jaw"><h4>Çene</h4></div>
      </div>

      <div class="dil-avatar-small-actions">
        <button class="primary" data-act="save">Ayarları kaydet</button>
        <button class="primary" data-act="testSpeak">Konuşma test</button>
        <button data-act="blink">Göz test</button>
        <button data-mouth="rest">rest</button>
        <button data-mouth="open">open</button>
        <button data-mouth="round">round</button>
        <button data-mouth="wide">wide</button>
        <button data-mouth="closed">closed</button>
        <button data-mouth="teeth">teeth</button>
        <button data-act="resetCurrent">Bu avatarı sıfırla</button>
        <button data-act="export">JSON getir</button>
        <button data-act="import">JSON yükle</button>
      </div>

      <textarea class="dil-avatar-json" placeholder="JSON ayarları burada görünür / buraya yapıştırılır"></textarea>
    `;

    host.innerHTML = "";
    host.appendChild(panel);

    state.saveStatusEl = panel.querySelector("[data-da-save-status]");
    state.dirty = false;
    updateSaveStatus("Kaydedildi");

    var mouth = panel.querySelector('[data-section="mouth"]');
    var eyes  = panel.querySelector('[data-section="eyes"]');
    var brow  = panel.querySelector('[data-section="brow"]');
    var jaw   = panel.querySelector('[data-section="jaw"]');

    addRange(mouth, "mouthX", "Ağız X", 250, 750, 1);
    addRange(mouth, "mouthY", "Ağız Y", 350, 780, 1);
    addRange(mouth, "mouthScale", "Ağız ölçek", 0.25, 2.2, 0.01);
    addRange(mouth, "mouthWidth", "Ağız genişlik", 20, 230, 1);
    addRange(mouth, "mouthHeight", "Ağız yükseklik", 6, 150, 1);
    addRange(mouth, "mouthRotate", "Ağız açı", -45, 45, 1);
    addRange(mouth, "mouthOpacity", "Ağız opaklık", 0, 1, 0.01);

    addRange(eyes, "leftEyeX", "Sol göz X", 250, 530, 1);
    addRange(eyes, "leftEyeY", "Sol göz Y", 250, 570, 1);
    addRange(eyes, "rightEyeX", "Sağ göz X", 470, 750, 1);
    addRange(eyes, "rightEyeY", "Sağ göz Y", 250, 570, 1);
    addRange(eyes, "eyeW", "Kapak genişlik", 20, 160, 1);
    addRange(eyes, "eyeH", "Kapak yükseklik", 6, 90, 1);
    addRange(eyes, "eyeStroke", "Kapak kalınlık", 1, 24, 1);
    addRange(eyes, "eyeCurve", "Kapak eğrisi", -40, 70, 1);
    addRange(eyes, "eyeOpacity", "Kapak opaklık", 0, 1, 0.01);

    addCheckbox(brow, "browVisible", "Kaş göster");
    addRange(brow, "browOpacity", "Kaş opaklık", 0, 1, 0.01);
    addRange(brow, "browWidth", "Kaş genişlik", 20, 180, 1);
    addRange(brow, "browHeight", "Kaş yükseklik", 0, 80, 1);
    addRange(brow, "browPeak", "Kaş tepe", -20, 80, 1);
    addRange(brow, "browStroke", "Kaş kalınlık", 1, 30, 1);
    addRange(brow, "leftBrowX", "Sol kaş X", 250, 530, 1);
    addRange(brow, "leftBrowY", "Sol kaş Y", 200, 520, 1);
    addRange(brow, "rightBrowX", "Sağ kaş X", 470, 750, 1);
    addRange(brow, "rightBrowY", "Sağ kaş Y", 200, 520, 1);
    addRange(brow, "leftBrowRotate", "Sol kaş açı", -60, 60, 1);
    addRange(brow, "rightBrowRotate", "Sağ kaş açı", -60, 60, 1);

    addCheckbox(jaw, "jawEnabled", "Çene aktif");
    addRange(jaw, "jawX", "Çene X", 250, 750, 1);
    addRange(jaw, "jawY", "Çene Y", 450, 860, 1);
    addRange(jaw, "jawWidth", "Çene genişlik", 30, 280, 1);
    addRange(jaw, "jawHeight", "Çene yükseklik", 10, 140, 1);
    addRange(jaw, "jawOpacity", "Çene opaklık", 0, 1, 0.01);
    addRange(jaw, "jawRest", "Rest hareket", 0, 20, 1);
    addRange(jaw, "jawClosed", "Closed hareket", 0, 20, 1);
    addRange(jaw, "jawWide", "Wide hareket", 0, 20, 1);
    addRange(jaw, "jawRound", "Round hareket", 0, 20, 1);
    addRange(jaw, "jawOpen", "Open hareket", 0, 32, 1);
    addRange(jaw, "jawTeeth", "Teeth hareket", 0, 20, 1);

    panel.addEventListener("click", function(ev){
      var b = ev.target.closest("button");
      if (!b) return;

      var m = b.getAttribute("data-mouth");
      if (m) setMouth(m);

      var act = b.getAttribute("data-act");
      if (act === "save") saveFromPanel();
      if (act === "blink") blinkOnce();
      if (act === "testSpeak") speakText("merhaba bugün ingilizce çalışıyoruz", 3200);

      if (act === "resetCurrent") {
        state.settings[state.gender] = clone(DEFAULTS[state.gender]);
        markDirty();
        render();
      }

      if (act === "export") {
        panel.querySelector(".dil-avatar-json").value = JSON.stringify(makePayload(), null, 2);
      }

      if (act === "import") {
        try {
          var data = JSON.parse(panel.querySelector(".dil-avatar-json").value);
          mergeIntoDefaults(state.settings, data);
          markDirty();
          render();
        } catch(e) {
          alert("JSON okunamadı.");
        }
      }
    });

    updateControlOutputs();
    return panel;
  }

  function getSettings(){
    if (!state.settings) loadSettings();
    return clone(state.settings);
  }

  function setSettings(obj){
    if (!state.settings) loadSettings();
    mergeIntoDefaults(state.settings, obj);
    saveSettings();
    render();
  }

  function forceReloadSettings(){
    loadSettings();
    render();
  }

  global.DilAvatar = {
    mount: mount,
    mountControlPanel: mountControlPanel,
    setMouth: setMouth,
    speakText: speakText,
    thinking: thinking,
    stop: function(){ stop(true); },
    setGender: setGender,
    getGender: getGender,
    visemeForChar: visemeForChar,
    blink: blinkOnce,
    getSettings: getSettings,
    setSettings: setSettings,
    forceReloadSettings: forceReloadSettings,
    saveSettingsNow: saveFromPanel
  };

})(window);
